def detect_parallel_conflicts(content_blocks):
    tool_results = [b for b in content_blocks if b.type == 'tool_result']
    conflicts = []
    for i, res1 in enumerate(tool_results):
        for res2 in tool_results[i+1:]:
            if abs(float(res1.content) - float(res2.content)) > 5:  # Threshold
                conflicts.append((res1.tool_use_id, res2.tool_use_id))
    return conflicts

