def safe_tool_chain(client, messages, tools):
    while True:
        response = client.messages.create(
            model="claude-3-5-sonnet-20240620",
            max_tokens=1024,
            tools=tools,
            messages=messages
        )

        last_content = response.content[-1]
        if last_content.type == 'tool_result' and 'error' in last_content.content.lower():
            messages.append({"role": "user", "content": "Tool failed. Stop and report error."})
            break

        if not any(b.type == 'tool_use' for b in response.content):
            break

        messages.extend(response.content)
    return response

def guarded_computer_use(client, screen_desc, action):
    confirmation_prompt = f"""
Screen: {screen_desc}
Proposed action: {action}

CRITICAL: Confirm this is exactly correct. Respond ONLY 'CONFIRMED' or 'CORRECTED: [new action]'.
"""

    confirm_resp = client.messages.create(
        model="claude-3-5-sonnet-20240620",
        max_tokens=20,
        messages=[{"role": "user", "content": confirmation_prompt}]
    )

    return 'CONFIRMED' in confirm_resp.content[0].text.upper()
